.header-navigation {
  padding: 30px 0;
  display: flex;
  align-items: center;
  justify-content: space-between;

  & .header-log {
    @media screen and (min-width: 768px) {
      width: 128px;
      height: 45px;
    }
  }

  & .header-svg {
    @media screen and (min-width: 768px) {
      width: 128px;
      height: 45px;
    }
  }
}

.header-link {
  display: none;

  z-index: 10;
  position: absolute;
}

.logo-light-theme {
  display: block;

  @media screen and (min-width: 1344px) {
    display: none;
  }
}

@media screen and (min-width: 320px) and (max-width: 767px) {
  .menu {
    margin-left: auto;
  }
}
@media screen and (min-width: 320px) {
  .menu {
    display: inline-flex;
    justify-content: center;

    border: none;
    background-color: transparent;
    fill: black;
    stroke: currentColor;
    z-index: 2;
    .header-cross {
      display: none;
    }
    &.is-open .header-cross {
      display: block;
      z-index: 100;
    }
    &.is-open .header-menu {
      display: none;
    }
  }

  .page-header {
    position: absolute;
    left: 0;
    right: 0;
  }


  .navigation-list {
    list-style: none;
    margin-bottom: 50px;
    @media screen and (max-width: 767px) {
      max-width: 320px;

      padding-left: 30px;
      margin-left: auto;
      margin-right: auto;
    }
  }

  .nav-link {
    color: var(--white-color);
    &:hover,
    &:focus {
      color: var(--orange-color);
    }
  }

  .button-call {
    display: none;
  }
  .button-call-menu {
    display: flex;
    justify-content: center;
    padding: 16px 0;
    margin: 0 auto;
    width: 260px;
    height: 48px;
    text-align: center;
    font-weight: bold;
    font-size: 12px;
    line-height: 1.25;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    background: transparent;
    color: var(--orange-color);
    border: 2px solid #ff6b09;
    box-sizing: border-box;
    transition-property: transform;
    transition-duration: 1500ms;
